import React, {useCallback,useEffect, useState} from 'react';
import { Button } from 'antd';
import { containerConstantsService } from '../utils/containerconstants/ContainerConstants';
import { RightOutlined } from '@ant-design/icons';
import BreadCrumb from './commoncomponent/breadcrumb/bread_crumb';
import { useStore } from './hook-store/store';
import {getBasePath} from './commoncomponent/BasePath';
import { Link } from 'react-router-dom';

const containerConstants = containerConstantsService.getInstance();

const LabelGeneration = (props) =>{
    let borderStyleFirst = { 'display':'flex', 'height': '40px', 'background': '#FFFFFF', 'border': '0.5px solid #DDDDDD', 'boxSizing': 'border-box', 'borderRadius': '4px', 'width': '100%'};

    let borderStyle = {'marginTop':'8px', 'display':'flex', 'height': '40px', 'background': '#FFFFFF', 'border': '0.5px solid #DDDDDD', 'boxSizing': 'border-box', 'borderRadius': '4px', 'width': '100%'};
    let leftTextStyle = {'alignSelf': 'center', 'width' : '80%', 'display':'flex', 'color': '#000000'};
    let rightArrowStyle = {'alignSelf': 'center', 'width' : '20%', 'display':'flex', 'justifyContent' : 'end', 'color': '#323232'};
    const [store, dispatch] = useStore(true);

    useEffect(() => {
        document.title = containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL);

        if( props.showCustom ){
            dispatch('SET_SHOW_CUSTOM', props.showCustom)
        }
        if( props.fromFCR  ){
            dispatch('SET_FROM_FCR', props.fromFCR)
        }
        if( props.isProduction ){
            dispatch('SET_IS_PRODUCTION',props.isProduction)
        }
        if( props.fromNewSetting ){
            dispatch('SET_IS_NEW_SETTING', props.fromNewSetting)    
        }

        
    },[])

    const dataValidationClick = (fromNewSetting) => {
        return fromNewSetting ? '/v2/new_settings/label_generation/data_validation'
                :
                getBasePath(props, store)+'/v2/label_generation/data_validation';
    }

    const awbGenerationClick = (fromNewSetting) => {
        return fromNewSetting ? '/v2/new_settings/label_generation/shipment_no_generation'
                :
                getBasePath(props, store)+'/v2/label_generation/shipment_no_generation';
    }

    const masterDataClick = (fromNewSetting) => {
        return fromNewSetting ? '/v2/new_settings/label_generation/carrier_allocation'
                :
                getBasePath(props, store)+'/v2/label_generation/carrier_allocation';
    }
    
    const labelTempatesClick = (fromNewSetting) => {
        return fromNewSetting ? '/v2/new_settings/label_generation/label_templates'
                :
                getBasePath(props, store)+'/v2/label_generation/label_templates';
    }

    const reverseConnectorClick = (fromNewSetting) => {
        return fromNewSetting ? '/v2/new_settings/label_generation/reverse_connector'
                :
                getBasePath(props, store)+'/v2/label_generation/reverse_connector';
    }

    const bulkUploadClick = (fromNewSetting) => {
        return fromNewSetting ? '/v2/new_settings/label_generation/bulk_upload'
                :
                getBasePath(props, store)+'/v2/label_generation/bulk_upload';
    }

    const urlList=
    [
        {
            url: getBasePath(props, store)+'/v2/label_generation/v2/settings',
            heading: containerConstants.formatString(containerConstants.SETTINGS),
        },
        {
            url: getBasePath(props, store)+'/v2/label_generation/settings',
            heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
        }
    ];

    const urlListForNewSetting=
    [
        {
            url: '/v2/new_settings/label_generation/settings',
            heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
        }
    ];

    return (
        <>
            <BreadCrumb  urlList={store.fromNewSetting ? urlListForNewSetting : urlList} />
            <div style = {{display: 'flex',flexDirection : 'column', marginLeft: '16px',marginRight: '16px'}}>

                <Link to={dataValidationClick(store.fromNewSetting)} style={{ textDecoration: 'none' }} >
                    <Button type="text" style={borderStyleFirst} >
                        <div style = {leftTextStyle} >{containerConstants.formatString(containerConstants.DATA_VALIDATION)}</div>
                        <RightOutlined style = {rightArrowStyle} />
                    </Button>
                </Link>

                <Link to={masterDataClick(store.fromNewSetting)} style={{ textDecoration: 'none' }} >
                    <Button type="text" style={borderStyle} >
                        <div style = {leftTextStyle} >{containerConstants.formatString(containerConstants.CARRIER_ALLOCATION_AND_MASTER_VALIDATION)}</div>
                        <RightOutlined style = {rightArrowStyle} />
                    </Button>
                </Link>

                <Link to={awbGenerationClick(store.fromNewSetting)} style={{ textDecoration: 'none' }} >
                    <Button type="text" style={borderStyle} >
                        <div style = {leftTextStyle} >{containerConstants.formatString(containerConstants.AWB_GENERATION)}</div>
                        <RightOutlined style = {rightArrowStyle} />
                    </Button>
                </Link>

                <Link to={labelTempatesClick(store.fromNewSetting)} style={{ textDecoration: 'none' }} >
                    <Button type="text" style={borderStyle} >
                        <div style = {leftTextStyle} >{containerConstants.formatString(containerConstants.LABEL_TEMPLATES)}</div>
                        <RightOutlined style = {rightArrowStyle} />
                    </Button>
                </Link>

                <Link to={reverseConnectorClick(store.fromNewSetting)} style={{ textDecoration: 'none' }} >
                    <Button type="text" style={borderStyle} >
                        <div style = {leftTextStyle} >{containerConstants.formatString(containerConstants.REVERSE_CONNECTOR)}</div>
                        <RightOutlined style = {rightArrowStyle} />
                    </Button>
                </Link>

                <Link to={bulkUploadClick(store.fromNewSetting)} style={{ textDecoration: 'none' }} >
                    <Button type="text" style={borderStyle} >
                        <div style = {leftTextStyle} >{containerConstants.formatString(containerConstants.BULK_UPLOAD)}</div>
                        <RightOutlined style = {rightArrowStyle} />
                    </Button>
                </Link>
            </div>
        </>
    )
}
export default LabelGeneration;
